from load_utils_dwh import load_dimension_or_fact
def transform_dim_customer():
    load_dimension_or_fact('Dim_Customer', """SELECT c.customer_id, c.customer_name, CASE WHEN t.customer_id IS NOT NULL AND m.customer_id IS NOT NULL THEN 'Both' WHEN t.customer_id IS NOT NULL THEN 'Tourist' WHEN m.customer_id IS NOT NULL THEN 'Mail-order' ELSE 'Unknown' END as customer_type, t.tour_guide, m.postal_address, c.first_order_date, l.city_key FROM idb.Customer c LEFT JOIN idb.TouristCustomer t ON c.customer_id = t.customer_id LEFT JOIN idb.MailOrderCustomer m ON c.customer_id = m.customer_id LEFT JOIN dwh.Dim_Location l ON c.city_id = l.city_id WHERE c.first_order_date >= '{last_runtime}'""", ['customer_id', 'customer_name', 'customer_type', 'tour_guide', 'postal_address', 'first_order_date', 'city_key'], False)
